import React from "react";

function App() {
  return (
    <div
      style={{
        height: "100vh",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        fontSize: "3rem",
        color: "red",
        fontWeight: "bold",
        textAlign: "center",
      }}
    >
      ¡BALBOA ALERTA ESTÁ VIVO!
    </div>
  );
}

export default App;
